def parse_csv_dataset(csv_path: Path):
    if pd is not None:
        df = pd.read_csv(csv_path)
        return df
    rows = []
    with csv_path.open(newline="", encoding="utf-8") as f:
        reader = csv.DictReader(f)
        rows.extend(reader)
    return rows


def normalize_label(label):
    if isinstance(label, bytes):
        label = label.decode("utf-8")
    return str(label).strip()


def load_images_from_directory(directory: Path, class_list: Optional[List[str]] = None):
    if not directory.exists():
        return [], [], []
    if class_list is None:
        class_list = sorted([p.name for p in directory.iterdir() if p.is_dir()])
    images = []
    labels = []
    names = []
    for idx, cls in enumerate(class_list):
        class_dir = directory / cls
        if not class_dir.exists():
            continue
        for img_path in class_dir.rglob("*"):
            if img_path.is_file() and img_path.suffix.lower() in [".jpg", ".jpeg", ".png", ".bmp", ".gif", ".webp"]:
                try:
                    img = tf.keras.utils.load_img(img_path, target_size=input_shape[:2])
                    arr = tf.keras.utils.img_to_array(img)
                    images.append(arr)
                    labels.append(idx)
                    names.append(str(img_path))
                except Exception:
                    continue
    return np.array(images, dtype=np.float32), np.array(labels, dtype=np.int32), class_list


def load_images_from_upload(upload_file_storage):
    filename = secure_filename(upload_file_storage.filename or "")
    if not filename:
        raise ValueError("Missing filename")
    ext = Path(filename).suffix.lower()
    unique_name = f"{uuid.uuid4().hex}{ext}"
    save_path = IMAGE_DIR / unique_name
    upload_file_storage.save(save_path)
    return save_path


def dataset_from_user_uploads(images: List[Path], labels: List[str]):
    xs = []
    ys = []
    for img_path, label in zip(images, labels):
        img = tf.keras.utils.load_img(img_path, target_size=input_shape[:2])
        arr = tf.keras.utils.img_to_array(img)
        xs.append(arr)
        ys.append(label)
    return np.array(xs, dtype=np.float32), np.array(ys, dtype=np.int32)


def load_csv_samples(csv_files: List[Path]):
    items = []
    for csv_path in csv_files:
        data = parse_csv_dataset(csv_path)
        if pd is not None and hasattr(data, "columns"):
            items.append(data)
        else:
            items.append(data)
    return items


def infer_csv_schema(data):
    if pd is not None and hasattr(data, "columns"):
        cols = list(data.columns)
        return cols
    if len(data) == 0:
        return []
    return list(data[0].keys())


def extract_features_labels_from_csv(data, target_col: str):
    if pd is not None and hasattr(data, "columns"):
        y = data[target_col].astype(str).tolist()
        X = data.drop(columns=[target_col])
        X = pd.get_dummies(X)
        return X.to_numpy(dtype=np.float32), np.array(y)
    y = []
    X = []
    for row in data:
        row = dict(row)
        y.append(str(row.pop(target_col)).strip())
        X.append(row)
    if not X:
        return np.zeros((0, 0), dtype=np.float32), np.array(y)
    all_keys = sorted({k for row in X for k in row.keys()})
    X_mat = []
    for row in X:
        vals = []
        for k in all_keys:
            v = row.get(k, "")
            try:
                vals.append(float(v))
            except Exception:
                vals.append(0.0)
        X_mat.append(vals)
    return np.array(X_mat, dtype=np.float32), np.array(y)


def train_image_model_from_paths(image_paths: List[Path], labels: List[str], epochs: int = 3):
    global class_names
    if not image_paths:
        raise ValueError("No images provided")
    class_names = sorted(list(dict.fromkeys([normalize_label(x) for x in labels])))
    if len(class_names) < 2:
        raise ValueError("Need at least 2 classes")
    save_class_names(class_names)
    label_to_idx = {name: i for i, name in enumerate(class_names)}
    xs = []
    ys = []
    for img_path, label in zip(image_paths, labels):
        img = tf.keras.utils.load_img(img_path, target_size=input_shape[:2])
        arr = tf.keras.utils.img_to_array(img)
        xs.append(arr)
        ys.append(label_to_idx[normalize_label(label)])
    X = np.array(xs, dtype=np.float32)
    y = np.array(ys, dtype=np.int32)
    ds = tf.data.Dataset.from_tensor_slices((X, y)).shuffle(min(len(X), 1000)).batch(32).prefetch(tf.data.AUTOTUNE)
    model = build_model(len(class_names))
    model.fit(ds, epochs=epochs, verbose=0)
    set_model(model)
    return model


def train_csv_model(csv_path: Path, target_col: str, epochs: int = 10):
    data = parse_csv_dataset(csv_path)
    if pd is not None and hasattr(data, "columns"):
        if target_col not in data.columns:
            raise ValueError(f"target_col '{target_col}' not found in CSV")
        y_raw = data[target_col].astype(str).map(normalize_label).tolist()
        class_names_local = sorted(list(dict.fromkeys(y_raw)))
        if len(class_names_local) < 2:
            raise ValueError("Need at least 2 classes")
        save_class_names(class_names_local)
        label_to_idx = {name: i for i, name in enumerate(class_names_local)}
        X_df = data.drop(columns=[target_col])
        X_df = pd.get_dummies(X_df)
        X = X_df.to_numpy(dtype=np.float32)
        y = np.array([label_to_idx[v] for v in y_raw], dtype=np.int32)
        model = build_model(len(class_names_local), input_shape=(X.shape[1], 1, 1))
        model = tf.keras.Sequential([
            tf.keras.Input(shape=(X.shape[1],)),
            layers.Normalization(),
            layers.Dense(128, activation="relu"),
            layers.Dropout(0.2),
            layers.Dense(len(class_names_local), activation="softmax"),
        ])
        model.layers[1].adapt(X)
        model.compile(optimizer="adam", loss="sparse_categorical_crossentropy", metrics=["accuracy"])
        model.fit(X, y, epochs=epochs, batch_size=32, verbose=0)
        set_model(model)
        return model
    else:
        rows = data
        if not rows:
            raise ValueError("Empty CSV")
        y_raw = [normalize_label(r[target_col]) for r in rows if target_col in r]
        class_names_local = sorted(list(dict.fromkeys(y_raw)))
        if len(class_names_local) < 2:
            raise ValueError("Need at least 2 classes")
        save_class_names(class_names_local)
        label_to_idx = {name: i for i, name in enumerate(class_names_local)}
        keys = sorted({k for r in rows for k in r.keys() if k != target_col})
        X = []
        y = []
        for r in rows:
            if target_col not in r:
                continue
            vals = []
            for k in keys:
                try:
                    vals.append(float(r.get(k, 0) or 0))
                except Exception:
                    vals.append(0.0)
            X.append(vals)
            y.append(label_to_idx[normalize_label(r[target_col])])
        X = np.array(X, dtype=np.float32)
        y = np.array(y, dtype=np.int32)
        model = tf.keras.Sequential([
            tf.keras.Input(shape=(X.shape[1],)),
            layers.Normalization(),
            layers.Dense(128, activation="relu"),
            layers.Dropout(0.2),
            layers.Dense(len(class_names_local), activation="softmax"),
        ])
        model.layers[1].adapt(X)
        model.compile(optimizer="adam", loss="sparse_categorical_crossentropy", metrics=["accuracy"])
        model.fit(X, y, epochs=epochs, batch_size=32, verbose=0)
        set_model(model)
        return model


