@app.route("/train/image", methods=["POST"])
def train_image():
    epochs = int(request.form.get("epochs", 3))
    image_files = request.files.getlist("files")
    labels_json = request.form.get("labels")
    if not image_files or not labels_json:
        return jsonify({"error": "files and labels are required"}), 400
    try:
        labels = json.loads(labels_json)
    except Exception:
        return jsonify({"error": "labels must be JSON array"}), 400
    if len(labels) != len(image_files):
        return jsonify({"error": "labels count must match files count"}), 400
    saved_paths = []
    for f, label in zip(image_files, labels):
        label = normalize_label(label)
        class_dir = IMAGE_DIR / label
        class_dir.mkdir(parents=True, exist_ok=True)
        filename = secure_filename(f.filename or "")
        ext = Path(filename).suffix.lower()
        unique_name = f"{uuid.uuid4().hex}{ext}"
        save_path = class_dir / unique_name
        f.save(save_path)
        saved_paths.append(save_path)
    try:
        model = train_image_model_from_paths(saved_paths, [normalize_label(l) for l in labels], epochs=epochs)
    except Exception as e:
        return jsonify({"error": str(e)}), 400
    return jsonify({"status": "trained", "classes": class_names, "model_path": str(MODEL_PATH)})


