@app.route("/predict/image", methods=["POST"])
def predict_image():
    if "file" not in request.files:
        return jsonify({"error": "file is required"}), 400
    model = get_model()
    file_storage = request.files["file"]
    image = tf.keras.utils.load_img(file_storage, target_size=input_shape[:2])
    arr = tf.keras.utils.img_to_array(image)[None, ...]
    preds = model.predict(arr, verbose=0)[0]
    names = load_class_names()
    if not names:
        names = [f"class_{i}" for i in range(len(preds))]
    result = [{"class": names[i] if i < len(names) else str(i), "score": float(preds[i])} for i in np.argsort(preds)[::-1]]
    return jsonify({"predictions": result})


@app.route("/retrain", methods=["POST"])
def retrain():
    epochs = int(request.form.get("epochs", 3))
    mode = request.form.get("mode", "image")
    if mode == "image":
        image_root = IMAGE_DIR
        names = sorted([p.name for p in image_root.iterdir() if p.is_dir()])
        if len(names) < 2:
            return jsonify({"error": "Need at least 2 image classes"}), 400
        X, y, names = load_images_from_directory(image_root, names)
        if len(X) == 0:
            return jsonify({"error": "No image data found"}), 400
        save_class_names(names)
        ds = tf.data.Dataset.from_tensor_slices((X, y)).shuffle(min(len(X), 1000)).batch(32).prefetch(tf.data.AUTOTUNE)
        model = build_model(len(names))
        model.fit(ds, epochs=epochs, verbose=0)
        set_model(model)
        return jsonify({"status": "retrained", "classes": names})
    return jsonify({"error": "Unsupported mode"}), 400


@app.route("/export", methods=["GET"])
def export_model():
    if not MODEL_PATH.exists():
        return jsonify({"error": "No model available"}), 404
    return jsonify({"model_path": str(MODEL_PATH), "classes": load_class_names()})


@app.route("/reset", methods=["POST"])
def reset():
    global current_model, class_names
    with model_lock:
        current_model = None
    class_names = []
    if MODEL_PATH.exists():
        MODEL_PATH.unlink()
    if META_PATH.exists():
        META_PATH.unlink()
    if IMAGE_DIR.exists():
        shutil.rmtree(IMAGE_DIR)
    if CSV_DIR.exists():
        shutil.rmtree(CSV_DIR)
    if UPLOAD_DIR.exists():
        shutil.rmtree(UPLOAD_DIR)
    for p in [UPLOAD_DIR, CSV_DIR, IMAGE_DIR, MODEL_DIR]:
        p.mkdir(parents=True, exist_ok=True)
    return jsonify({"status": "reset"})


